import { Component, OnInit } from '@angular/core';
import { AdminService } from '../../../../core/services/admin.service';
import { ExportService } from '../../../../core/services/export.service';
import { HistoricoConsulta, User } from '../../../../core/models/models';

type Tab = 'historico' | 'utilizadores';

@Component({
  selector: 'app-admin-logs',
  templateUrl: './admin-logs.component.html',
  styleUrls: ['./admin-logs.component.scss'],
})
export class AdminLogsComponent implements OnInit {
  activeTab: Tab = 'historico';
  logs: (HistoricoConsulta & { utilizador?: string; email?: string })[] = [];
  filterText = '';
  users: User[] = [];
  usersFilter  = '';
  loading    = false;
  error      = '';
  successMsg = '';

  constructor(private adminSvc: AdminService, private exportSvc: ExportService) {}

  ngOnInit(): void { this.loadHistory(); this.loadUsers(); }
  setTab(tab: Tab): void { this.activeTab = tab; }

  loadHistory(): void {
    this.loading = true;
    this.adminSvc.getAllHistory(500).subscribe({
      next:  (r) => { this.logs = r.data ?? []; this.loading = false; },
      error: (e) => { this.error = e.error?.message ?? 'Erro.'; this.loading = false; },
    });
  }

  get filteredLogs() {
    const q = this.filterText.toLowerCase();
    return q ? this.logs.filter((l: any) =>
      l.cidade_consultada.toLowerCase().includes(q) ||
      (l.email ?? '').toLowerCase().includes(q) ||
      (l.utilizador ?? '').toLowerCase().includes(q)
    ) : this.logs;
  }

  exportCSV(): void { this.exportSvc.exportHistoricoCSV(this.filteredLogs); }
  exportPDF(): void { this.exportSvc.exportHistoricoPDF(this.filteredLogs, 'Admin'); }

  loadUsers(): void {
    this.adminSvc.getAllUsers().subscribe({
      next: (r) => this.users = r.data ?? [],
      error: () => {},
    });
  }

  get filteredUsers() {
    const q = this.usersFilter.toLowerCase();
    return q ? this.users.filter(u =>
      u.nome.toLowerCase().includes(q) || u.email.toLowerCase().includes(q)
    ) : this.users;
  }

  toggleRole(user: User): void {
    const newRole: 'admin' | 'utilizador' = user.role === 'admin' ? 'utilizador' : 'admin';
    if (!confirm(`Alterar role de "${user.nome}" para "${newRole}"?`)) return;
    this.adminSvc.updateRole(user.id, newRole).subscribe({
      next: () => { user.role = newRole; this.successMsg = `Role de ${user.nome} → ${newRole}.`; },
      error: (e: any) => this.error = e.error?.message,
    });
  }

  deleteUser(user: User): void {
    if (!confirm(`Eliminar "${user.nome}"? Esta acção é irreversível.`)) return;
    this.adminSvc.deleteUser(user.id).subscribe({
      next: () => { this.users = this.users.filter(u => u.id !== user.id); this.successMsg = 'Utilizador eliminado.'; },
      error: (e: any) => this.error = e.error?.message,
    });
  }
}
<div class="page-container">
  <div class="page-header">
    <h1>{{ 'admin.title' | translate }}</h1>
    <div class="page-actions" *ngIf="activeTab === 'historico'">
      <app-export-panel (exportCSV)="exportCSV()" (exportPDF)="exportPDF()"></app-export-panel>
    </div>
  </div>

  <app-alert [message]="error"      type="error"   (dismiss)="error=''"></app-alert>
  <app-alert [message]="successMsg" type="success" (dismiss)="successMsg=''"></app-alert>

  <!-- Tabs -->
  <div class="tabs">
    <button class="tab-btn" [class.active]="activeTab==='historico'" (click)="setTab('historico')">
      📋 Histórico Global
    </button>
    <button class="tab-btn" [class.active]="activeTab==='utilizadores'" (click)="setTab('utilizadores')">
      👥 Utilizadores
    </button>
  </div>

  <!-- ── HISTORY TAB ──────────────────────────────────────────────────────── -->
  <div *ngIf="activeTab === 'historico'">
    <div class="table-toolbar">
      <input type="text" [(ngModel)]="filterText"
        placeholder="Filtrar por cidade, email ou utilizador..."
        class="table-search" />
      <span class="record-count">{{ filteredLogs.length }} registos</span>
    </div>

    <app-loading-spinner [loading]="loading"></app-loading-spinner>

    <div class="table-wrapper" *ngIf="!loading">
      <table class="data-table" *ngIf="filteredLogs.length; else emptyH">
        <thead>
          <tr>
            <th>#</th>
            <th>{{ 'admin.user' | translate }}</th>
            <th>Email</th>
            <th>{{ 'history.city' | translate }}</th>
            <th>{{ 'history.temp' | translate }}</th>
            <th>{{ 'history.climate' | translate }}</th>
            <th>{{ 'history.date' | translate }}</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let l of filteredLogs; let i = index">
            <td class="muted">{{ i + 1 }}</td>
            <td>{{ l['utilizador'] || '—' }}</td>
            <td class="muted">{{ l['email'] || '—' }}</td>
            <td><strong>{{ l.cidade_consultada }}</strong></td>
            <td><span class="temp-badge">{{ l.temperatura }}°C</span></td>
            <td>{{ l.clima | titlecase }}</td>
            <td class="date-cell">{{ l.data_consulta | date:'dd/MM/yy HH:mm' }}</td>
          </tr>
        </tbody>
      </table>
      <ng-template #emptyH>
        <div class="empty-state">
          <div class="empty-icon">📋</div>
          <p>{{ 'common.noData' | translate }}</p>
        </div>
      </ng-template>
    </div>
  </div>

  <!-- ── USERS TAB ────────────────────────────────────────────────────────── -->
  <div *ngIf="activeTab === 'utilizadores'">
    <div class="table-toolbar">
      <input type="text" [(ngModel)]="usersFilter"
        placeholder="Filtrar por nome ou email..."
        class="table-search" />
      <span class="record-count">{{ filteredUsers.length }} utilizadores</span>
    </div>

    <div class="table-wrapper">
      <table class="data-table" *ngIf="filteredUsers.length; else emptyU">
        <thead>
          <tr>
            <th>ID</th>
            <th>Nome</th>
            <th>Email</th>
            <th>Role</th>
            <th>Criado Em</th>
            <th>Acções</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let u of filteredUsers">
            <td class="muted">{{ u.id }}</td>
            <td><strong>{{ u.nome }}</strong></td>
            <td class="muted">{{ u.email }}</td>
            <td>
              <span class="role-badge" [class.admin]="u.role === 'admin'">
                {{ u.role }}
              </span>
            </td>
            <td class="date-cell">{{ u.criado_em | date:'dd/MM/yyyy' }}</td>
            <td>
              <div class="row-actions">
                <button class="btn btn-secondary btn-sm" (click)="toggleRole(u)"
                  title="Alternar role">
                  🔄 {{ u.role === 'admin' ? 'Tornar user' : 'Tornar admin' }}
                </button>
                <button class="btn btn-danger btn-sm" (click)="deleteUser(u)"
                  title="Eliminar utilizador">
                  🗑️
                </button>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
      <ng-template #emptyU>
        <div class="empty-state">
          <div class="empty-icon">👥</div>
          <p>Nenhum utilizador encontrado</p>
        </div>
      </ng-template>
    </div>
  </div>
</div>
